// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ItemSession) predicate.ItemSession {
	return predicate.ItemSession(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ItemSession) predicate.ItemSession {
	return predicate.ItemSession(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ItemSession) predicate.ItemSession {
	return predicate.ItemSession(sql.NotPredicates(p))
}
